type Props = { result: ForgeResult }

function toSlug(title: string) {
  return title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '') + '.md'
}

function colorLine(line: string): string {
  if (line.startsWith('#')) return '#E05C15'
  if (line.startsWith('-') || line.startsWith('*')) return '#A8D8A4'
  if (line.startsWith('â†’')) return '#7AB8F5'
  if (line.startsWith('[Source')) return '#777'
  return '#E6E4DC'
}

function CopyIcon() {
  return (
    <svg viewBox="0 0 24 24" width="13" height="13" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="9" y="9" width="13" height="13" rx="2" ry="2" />
      <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" />
    </svg>
  )
}

