async function generateShareCaption(claudeMd: string, skills: ForgeResult['skills'], tags: string[]): Promise<string> {
  const res = await fetch('/api/test-drive', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      messages: [
        { role: 'system', content: 'You are a developer tweet writer. Generate a single engaging tweet (under 220 characters) for a developer who just generated a custom CLAUDE.md setup. Mention the stack/skills if interesting. Include #ClaudeCode at the end. Output ONLY the tweet text â€” no quotes, no preamble.' },
        { role: 'user', content: `Stack: ${tags.join(', ')}\nSkills: ${skills.map(s => s.title).join(', ')}\n\nCLAUDE.md preview:\n${claudeMd.slice(0, 500)}` },
      ],
    }),
  })
  const data = await res.json()
  return (data.content as string) ?? `Just forged my perfect CLAUDE.md with ${skills.length} skills for ${tags.slice(0, 2).join(' + ')} â€” claudemdforge.site #ClaudeCode`
}

